98	// authCancelPatterns are regexps matched against lowercased stderr lines that indicate
99	// the subprocess will never succeed and should be cancelled immediately.
100	// Numeric HTTP codes use word-boundary anchors to avoid false positives (e.g. "port 4290").
101	// Overly broad patterns like "credential" and "please run" are intentionally excluded.
102	var authCancelPatterns = []*regexp.Regexp{
103		regexp.MustCompile(`\b429\b`),
104		regexp.MustCompile(`\b401\b`),
105		regexp.MustCompile(`\b403\b`),
106		regexp.MustCompile(`rate limit`),
107		regexp.MustCompile(`ratelimit`),
108		regexp.MustCompile(`quota exceeded`),
109		regexp.MustCompile(`quota_exceeded`),
110		regexp.MustCompile(`not logged in`),
111		regexp.MustCompile(`not signed in`),
112		regexp.MustCompile(`no credentials`),
113		regexp.MustCompile(`authentication required`),
114		regexp.MustCompile(`authentication failed`),
115		regexp.MustCompile(`unauthorized`),
116		regexp.MustCompile(`unauthenticated`),
117		regexp.MustCompile(`invalid api key`),
118		regexp.MustCompile(`invalid_api_key`),
119		regexp.MustCompile(`api key not found`),
120		regexp.MustCompile(`insufficient credits`),
121		regexp.MustCompile(`insufficient_credits`),
122		regexp.MustCompile(`login required`),
123		regexp.MustCompile(`api key expired`),
124		regexp.MustCompile(`token expired`),
125	}
126	
127	// matchesCancelPattern returns the matched pattern string if line matches a known
128	// auth/rate-limit pattern that warrants early cancellation, empty string otherwise.
129	func matchesCancelPattern(line string) string {
130		lower := strings.ToLower(line)
131		for _, p := range authCancelPatterns {
132			if p.MatchString(lower) {
133				return p.String()
134			}
135		}
136		return ""
137	}
