139	// OSExecutor executes commands via os/exec.
140	type OSExecutor struct{}
141	
142	// Execute runs a command and captures output.
143	func (e *OSExecutor) Execute(ctx context.Context, binary string, args []string, stdin string) (*ExecResult, error) {
144		return e.ExecuteInDir(ctx, binary, args, stdin, "")
145	}
